import React, { useEffect, useState, useRef } from 'react';
import { uploadDocument } from '../api/uploadDocument';
import { listDocuments } from '../api/listDocuments';

export default function DocumentsPage() {
  const fileRef = useRef(null);
  const [docs, setDocs] = useState([]);
  const [uploading, setUploading] = useState(false);
  const [progress, setProgress] = useState(0);
  const [error, setError] = useState('');

  const loadDocs = async () => {
    try {
      const resp = await listDocuments();
      setDocs(resp?.data?.documents || []);
    } catch (e) {
      setError('Failed to load documents');
    }
  };

  useEffect(() => {
    loadDocs();
  }, []);

  const onUpload = async (file) => {
    setUploading(true);
    setError('');
    setProgress(0);

    try {
      await uploadDocument(file, setProgress);
      await loadDocs(); // refresh list after upload
    } catch (e) {
      setError('Upload failed');
    } finally {
      setUploading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-6">
      <h1 className="text-2xl font-bold mb-4">My Documents</h1>

      <input
        ref={fileRef}
        type="file"
        className="hidden"
        onChange={(e) => e.target.files && onUpload(e.target.files[0])}
      />

      <button
        onClick={() => fileRef.current?.click()}
        className="px-4 py-2 bg-blue-600 text-white rounded"
      >
        Upload Document
      </button>

      {uploading && (
        <div className="mt-3 text-sm">
          Uploading… {progress}%
        </div>
      )}

      {error && <div className="mt-3 text-red-600">{error}</div>}

      <ul className="mt-6 space-y-2">
        {docs.map((d) => (
          <li
            key={d.documentId}
            className="border rounded p-3 bg-white"
          >
            <div className="font-medium">{d.filename}</div>
            <div className="text-xs text-slate-500">{d.filePath}</div>
          </li>
        ))}
      </ul>
    </div>
  );
}
